using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// A resolver that only handles the Person type — simulates a limited
// source-generated context where not every type has metadata.
var limitedResolver = new LimitedResolver();

var options = new JsonSerializerOptions { TypeInfoResolver = limitedResolver };

// ─── 1. Strongly-typed retrieval: GetTypeInfo<T>() → JsonTypeInfo<T> ───
JsonTypeInfo<Person> typedInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got JsonTypeInfo<{typedInfo.Type.Name}> (kind: {typedInfo.Kind})");

// ─── 2. Probe without throwing: TryGetTypeInfo<T>() → bool ───
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? personInfo))
    Console.WriteLine($"TryGetTypeInfo<Person> → true  (type: {personInfo!.Type.Name})");

if (!options.TryGetTypeInfo<Order>(out JsonTypeInfo<Order>? _))
    Console.WriteLine("TryGetTypeInfo<Order>  → false (no exception thrown!)");

// ─── Types ───
record Person(string Name, int Age);
record Order(int Id);

// ─── Custom resolver that only resolves Person ───
class LimitedResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
        => type == typeof(Person) ? _inner.GetTypeInfo(type, options) : null;
}

